configuration.jsScript:
/* get the attributes of the devices as a key */
var validKeys = Object.keys(metadata).filter(k => k.startsWith('shared_')).map(k => k.replace('shared_', ''));

/* get the attributes inside the message to check as keys */
var incomingKeys = Object.keys(msg);

/* check if the keys are included, 
otherwise add them to the list */
var wrongTelemetryAttributes = [];
for(var currenKey in incomingKeys){
    if(!validKeys.includes(currenKey))
        wrongTelemetryAttributes.push(currenKey);
}

/* add a new field to metadata */
metadata.wrongTelemetryAttributes = JSON.stringify(wrongTelemetryAttributes);

return {msg:msg,metadata:metadata,msgType:msgType}; // return the changed message

var wrongTelemetryAttributes = JSON.parse(metadata.wrongTelemetryAttributes); // get the wrong attributes

/* if the metadata attribute exists and the list is empty the message is valid */
if(wrongTelemetryAttributes && wrongTelemetryAttributes.length === 0)
    return ['valid'];

return ['invalid']; //otherwise it's invalid

