if(msgType == 'POST_TELEMETRY_REQUEST') {
    return ['two'];
}
return nextRelation(metadata, msg);

configuration.alarmDetailsBuildJs:
var wrongKeysList = JSON.parse(metadata
    .wrongTelemetryAttributes); // get the attributes
var wrongKeysString = "";

for(var i=0;i<wrongKeysList.length;i++){
    wrongKeysString += wrongKeysList[i]; // add the key
    if(i!=wrongKeysList.length-1) // check if it's possibile to add a comma
        wrongKeysString += ","

    wrongKeysString += " "; // add a space
}

return 'Telemetry attributes ' + wrongKeysString + 'not found in device '+metadata.deviceName;

configuration.alarmDetailsBuildTbel:
var details = {};
if (metadata.prevAlarmDetails != null) {
    details = JSON.parse(metadata.prevAlarmDetails);
    //remove prevAlarmDetails from metadata
    metadata.remove('prevAlarmDetails');
    //now metadata is the same as it comes IN this rule node
}


return details;

configuration.jsScript:
var invalidKeys = JSON.parse(metadata.wrongTelemetryKeys); // get wrong keys 
var newMessage = {}; // create new new message 
var messageKeys = Object.keys(msg); // get the keys of the message

/* copy only the keys that are not 
in the list of invalid keys */
for(var currentKey in messageKeys){
    if(!invalidKeys.includes(currentKey))
        newMessage[currentKey] = msg[currentKey];
}

delete metadata.wrongTelemetryKeys; // delete the attribute after the transformation

/* return the new formatted message */
return {msg:newMessage, metadata:metadata, msgType:msgType};
